noncompliant:
// Noncompliant: #include preceded by non-preprocessor code
int globalVar = 10;  // Code before include
#include <stdio.h>

void function() {
    printf("Hello");
}

compliant:
// Compliant: #include only preceded by comments and preprocessor directives
/* File header comment */
#define VERSION 1.0
#include <stdio.h>
#include "myheader.h"

int globalVar = 10;  // Code after includes
